import React, { useState, useEffect } from "react";
import Hamburger from "./Ui/Hamburger";

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  // Prevent body scrolling when menu is open
  useEffect(() => {
    if (isMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'auto';
    }
    
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, [isMenuOpen]);

  // Navigation links data
  const navLinks = [
    { path: "/", label: "Home" },
    { path: "/services", label: "Services" },
    { path: "/about", label: "About" },
    { path: "/contact", label: "Contact" }
  ];

  // Render navigation links
  const renderNavLinks = (isMobile = false) => (
    <>
      {navLinks.map((link) => (
        <a 
          key={link.path} 
          href={link.path}
          {...(isMobile && { onClick: toggleMenu })}
        >
          {link.label}
        </a>
      ))}
    </>
  );

  return (
    <header className=" navbar-header-main-container">
    <div className="navbar-container container">
        {/* Background Clouds */}
      <div className="clouds" aria-hidden="true">
        <picture>
          <source
            media="(max-width: 600px)"
            srcSet="./Images/header/cloud-top.svg"
          />
          <img
            src="./Images/header/cloud-top.svg"
            alt=""
            className="cloud-top"
          />
        </picture>
        <picture>
          <source
            media="(max-width: 600px)"
            srcSet="./Images/header/cloud-bottom.svg"
          />
          <img
            src="./Images/header/cloud-bottom.svg"
            alt=""
            className="cloud-bottom"
          />
        </picture>
      </div>
   
      {/* Actual Navbar Content */}
      <div className="navbar-content">
        <div className="nav-links-container container">
          <figure className="header-logo">
            <img src="./logo/logo.avif" alt="Company Logo" className="main-logo" />
            <figcaption className="header-logo-caption">
              <div className="header-ratings-container">
                <p className="header-ratings">4,8</p>
                <div className="header-ratings-stars">
                  {[...Array(5)].map((_, i) => (
                    <img
                      key={i}
                      height={30}
                      width={30}
                      src="./Images/header/star.svg"
                      alt="website ratings"
                    />
                  ))}
                </div>
              </div>
              <span className="header-total-counts">2,290 ratings</span>
            </figcaption>
          </figure>

          <Hamburger isOpen={isMenuOpen} toggleMenu={toggleMenu} />

          {/* Desktop Navigation */}
          <nav className="nav-links" role="navigation" aria-label="Main navigation">
            {renderNavLinks()}
          </nav>
          
          {/* Mobile Navigation */}
          <div className={`mobile-menu ${isMenuOpen ? 'open' : ''}`}>
            <nav className="mobile-nav-links" role="navigation" aria-label="Mobile navigation">
              {renderNavLinks(true)}
            </nav>
          </div>
        </div>
      </div>
    </div>
    </header>
  );
};

export default Navbar;